import React from "react";
import { Routes, Route } from "react-router-dom";

import SignUp from "./components/SignUp";
import Login from "./components/Login";

import Admin from "./components/Admin";

function App() {
  return (
    <Routes>

      {/* Signup Page */}
      <Route
        path="/send-otp"
        element={<SignUp />}
      />

      {/* OTP Verification Page */}
      <Route
        path="/verify-otp"
        element={<Login />}
      />

        {/* Signup Page */}
      <Route
        path="/"
        element={<Admin />}
      />


    </Routes>
  );
}

export default App;




